import React, { useState, useEffect } from 'react';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { auth } from './firebase';
import api from './api';
import LoginAdmin from './components/LoginAdmin';
import Servicios from './components/Servicios';
import Usuarios from './components/Usuarios';
import Dashboard from './components/Dashboard';
import Emergencias from './components/Emergencias';
import './App.css';

export default function App() {
  const [usuario, setUsuario] = useState(null);
  const [perfil, setPerfil] = useState(null);
  const [cargando, setCargando] = useState(true);
  const [errorAcceso, setErrorAcceso] = useState('');
  const [tab, setTab] = useState('dashboard');

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (user) => {
      if (user) {
        setUsuario(user);
        try {
          // Verificar que el usuario tenga rol admin
          const res = await api.get(`/auth/perfil/${user.uid}`);
          if (res.data.rol === 'admin') {
            setPerfil(res.data);
            setErrorAcceso('');
          } else {
            setErrorAcceso('Tu cuenta no tiene permisos de administrador.');
            setPerfil(null);
            await signOut(auth);
          }
        } catch (err) {
          setErrorAcceso('Error al verificar permisos. Intenta de nuevo.');
          setPerfil(null);
          await signOut(auth);
        }
      } else {
        setUsuario(null);
        setPerfil(null);
      }
      setCargando(false);
    });
    return unsub;
  }, []);

  const cerrarSesion = async () => {
    await signOut(auth);
    setTab('dashboard');
  };

  if (cargando) {
    return (
      <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#f5f5f5' }}>
        <p style={{ fontSize: 18, color: '#999' }}>Cargando...</p>
      </div>
    );
  }

  // Si no hay sesión o no es admin, mostrar login
  if (!usuario || !perfil) {
    return <LoginAdmin errorExterno={errorAcceso} />;
  }

  return (
    <div className="app">
      <header className="header">
        <div style={{ flex: 1 }}>
          <h1>🚕 UntaXtame S.A.S</h1>
          <p>Panel Administrador — {perfil.nombre}</p>
        </div>
        <button onClick={cerrarSesion} style={{
          background: 'rgba(0,0,0,0.15)', border: 'none', borderRadius: 8,
          padding: '8px 16px', cursor: 'pointer', fontWeight: 'bold', fontSize: 14
        }}>
          Cerrar sesión
        </button>
      </header>
      <nav className="nav">
        <button className={tab === 'dashboard' ? 'active' : ''} onClick={() => setTab('dashboard')}>
          📊 Dashboard
        </button>
        <button className={tab === 'servicios' ? 'active' : ''} onClick={() => setTab('servicios')}>
          📋 Servicios
        </button>
        <button className={tab === 'usuarios' ? 'active' : ''} onClick={() => setTab('usuarios')}>
          👥 Usuarios
        </button>
        <button className={tab === 'emergencias' ? 'active' : ''} onClick={() => setTab('emergencias')}>
          🚨 Emergencias
        </button>
      </nav>
      <main className="main">
        {tab === 'dashboard' && <Dashboard />}
        {tab === 'servicios' && <Servicios />}
        {tab === 'usuarios' && <Usuarios />}
        {tab === 'emergencias' && <Emergencias />}
      </main>
    </div>
  );
}
